import React, { useState, useEffect } from 'react';

const Trips = () => {
  const [itinerary, setItinerary] = useState([]);

  useEffect(() => {
    loadItinerary();
  }, []);

  const loadItinerary = () => {
    const saved = JSON.parse(localStorage.getItem('itinerary') || '[]');
    setItinerary(saved);
  };

  const removeFromItinerary = (placeId) => {
    const updated = itinerary.filter(place => place.id !== placeId);
    setItinerary(updated);
    localStorage.setItem('itinerary', JSON.stringify(updated));
  };

  const getTotalCost = () => {
    return itinerary.reduce((total, place) => total + parseFloat(place.price), 0);
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <h1 style={styles.title}>My Trips</h1>
      </div>

      {userTrips.length === 0 ? (
        <div style={styles.noTrips}>
          <h3>No trips yet</h3>
          <p>Start exploring places to create your first trip!</p>
          <a href="/places" style={styles.exploreButton}>Explore Places</a>
        </div>
      ) : (
        <div style={styles.tripsGrid}>
          {userTrips.map(trip => (
            <div key={trip.id} style={styles.tripCard}>
              <h3 style={styles.tripName}>{trip.name}</h3>
              <p style={styles.tripBudget}>Budget: NPR {trip.budget}</p>
              <p style={styles.tripDate}>Created: {new Date(trip.created_at).toLocaleDateString()}</p>
            </div>
          ))}
        </div>
      )}
    </div>
  );
};

const styles = {
  container: {
    maxWidth: '1200px',
    margin: '0 auto',
    padding: '2rem',
    backgroundColor: '#f8fafc',
    minHeight: '100vh'
  },
  header: {
    backgroundColor: 'white',
    padding: '2rem',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)',
    marginBottom: '2rem'
  },
  title: {
    color: '#1f2937',
    fontSize: '2.5rem',
    fontWeight: '700',
    margin: 0
  },
  noTrips: {
    textAlign: 'center',
    padding: '3rem',
    backgroundColor: 'white',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
  },
  exploreButton: {
    backgroundColor: '#3b82f6',
    color: 'white',
    padding: '0.75rem 1.5rem',
    borderRadius: '8px',
    textDecoration: 'none',
    fontWeight: '600',
    display: 'inline-block',
    marginTop: '1rem'
  },
  tripsGrid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(auto-fill, minmax(300px, 1fr))',
    gap: '2rem'
  },
  tripCard: {
    backgroundColor: 'white',
    padding: '2rem',
    borderRadius: '12px',
    boxShadow: '0 4px 6px -1px rgba(0, 0, 0, 0.1)'
  },
  tripName: {
    fontSize: '1.25rem',
    fontWeight: '700',
    color: '#1f2937',
    margin: '0 0 1rem 0'
  },
  tripBudget: {
    color: '#059669',
    fontWeight: '600',
    margin: '0 0 0.5rem 0'
  },
  tripDate: {
    color: '#6b7280',
    fontSize: '0.9rem',
    margin: 0
  }
};

export default Trips;
